// harness 提供的是 div；在容器内建立 Tagify 所需的原生 input
const el = document.getElementById('tags'); const input = document.createElement('input'); input.setAttribute('aria-label', 'Tags'); el.appendChild(input);
const css = document.createElement('link'); css.rel='stylesheet'; css.href='https://cdn.jsdelivr.net/npm/@yaireo/tagify@4.38.0/dist/tagify.css'; document.head.appendChild(css);
const { default: Tagify } = await import('https://cdn.jsdelivr.net/npm/@yaireo/tagify@4.38.0/+esm');
const tagify = new Tagify(input, { whitelist: data.whitelist ?? [], enforceWhitelist: data.enforceWhitelist ?? false, maxTags: data.maxTags ?? Infinity, dropdown: { enabled: 1, maxItems: 20 } });
if (data.initialValue) tagify.addTags(data.initialValue);
// 取产物: tagify.value(数组) / tagify.getCleanValue()

