import Tagify from 'https://cdn.jsdelivr.net/npm/@yaireo/tagify@4.38.0/+esm';
const css = document.createElement('link'); css.rel='stylesheet'; css.href='https://cdn.jsdelivr.net/npm/@yaireo/tagify@4.38.0/dist/tagify.css'; shadowRoot.appendChild(css);
const input = document.createElement('input'); shadowRoot.appendChild(input);
const host = document.createElement('div'); shadowRoot.appendChild(host);
// appendTarget 让建议下拉留在 shadow(默认下拉 append 到 document.body,逃出 shadow 失去样式)
const tagify = new Tagify(input, { whitelist: data.whitelist ?? [], dropdown: { enabled: 1, appendTarget: host } });

